def gen(rng, size):
    n = rng.randint(1, max(1, size))
    arr = []
    while len(arr) < n:
        if rng.random() < 0.5:
            start = rng.randint(-1000, 1000)
            d = rng.randint(-5, 5)
            runlen = rng.randint(1, 8)
            v = start
            for _ in range(runlen):
                if len(arr) >= n:
                    break
                arr.append(max(-1000, min(1000, v)))
                v += d
        else:
            arr.append(rng.randint(-1000, 1000))
    return [arr[:n]]

