class Solution:
    def numberOfArithmeticSlices(self, nums):
        n = len(nums)
        total = 0
        for i in range(n - 2):
            d = nums[i + 1] - nums[i]
            j = i + 2
            while j < n and nums[j] - nums[j - 1] == d:
                total += 1
                j += 1
        return total

